mapper.select:
SELECT a.id, a.title, a.notice_type AS noticeType, a.status, a.top_flag AS topFlag, a.publish_time AS publishTime, a.expire_time AS expireTime, CASE WHEN a.expire_time IS NOT NULL AND a.expire_time < NOW() THEN TRUE ELSE FALSE END AS expired FROM nt_announcement a WHERE a.del_flag = 0
AND a.title LIKE CONCAT('%', #{query.title}, '%')
AND a.notice_type = #{query.noticeType}
AND a.status = #{query.status}
AND a.create_time >= #{query.startTime}
AND a.create_time <= #{query.endTime}
ORDER BY a.top_flag DESC, a.publish_time DESC, a.id DESC

SELECT a.id, a.title, a.notice_type AS noticeType, a.status, a.top_flag AS topFlag, a.publish_time AS publishTime, a.expire_time AS expireTime, CASE WHEN a.expire_time IS NOT NULL AND a.expire_time < NOW() THEN TRUE ELSE FALSE END AS expired, CASE WHEN rr.id IS NOT NULL THEN TRUE ELSE FALSE END AS `read` FROM nt_announcement a INNER JOIN nt_announcement_target_snapshot ts ON ts.announcement_id = a.id AND ts.user_id = #{userId} LEFT JOIN nt_announcement_read_record rr ON rr.announcement_id = a.id AND rr.user_id = #{userId} WHERE a.del_flag = 0 AND a.status = 'PUBLISHED' AND (a.expire_time IS NULL OR a.expire_time >= NOW())
AND a.notice_type = #{noticeType}
ORDER BY a.top_flag DESC, a.publish_time DESC, a.id DESC
